#ifndef I2C_SCANNER_H
#define I2C_SCANNER_H
#include <Arduino.h>

typedef struct {
  uint8_t address;
  const char* name;
  const char* type;
} i2c_device_t;

int i2c_scan(i2c_device_t* devices, int max_devices);
const char* i2c_identify(uint8_t address);
void i2c_print_manifest();

#endif

firmware_template.source:
#include "i2c_scanner.h"
#include <Wire.h>

typedef struct { uint8_t addr; const char* name; } known_device_t;

static const known_device_t known_devices[] = {
  {0x23, "BH1750"}, {0x38, "AHT10/AHT20"}, {0x39, "APDS-9960"},
  {0x3C, "SSD1306"}, {0x3D, "SH1106"}, {0x40, "INA219"},
  {0x44, "SHT31"}, {0x48, "ADS1115"}, {0x49, "TSL2561"},
  {0x50, "AT24C32"}, {0x57, "MAX30102"}, {0x5A, "MLX90614"},
  {0x5B, "CCS811"}, {0x60, "SI1145"}, {0x62, "SCD40"},
  {0x68, "MPU6050/DS3231"}, {0x69, "MPU6050-ALT"},
  {0x76, "BME280/BMP280"}, {0x77, "BMP180/BME680"},
  {0x18, "MCP9808"}, {0x19, "LIS3DH"}, {0x1D, "ADXL345"},
  {0x29, "VL53L0X"}, {0x27, "LCD-I2C"}, {0x3F, "LCD-I2C-ALT"},
  {0x53, "ADXL345-ALT"}, {0x58, "SGP30"}, {0x70, "HT16K33"},
};

const char* i2c_identify(uint8_t address) {
  for (int i = 0; i < (int)(sizeof(known_devices)/sizeof(known_devices[0])); i++) {
    if (known_devices[i].addr == address) return known_devices[i].name;
  }
  return "unknown";
}

int i2c_scan(i2c_device_t* devices, int max_devices) {
  Wire.begin(8, 9);
  int count = 0;
  for (uint8_t addr = 1; addr < 127 && count < max_devices; addr++) {
    Wire.beginTransmission(addr);
    if (Wire.endTransmission() == 0) {
      devices[count].address = addr;
      devices[count].name = i2c_identify(addr);
      devices[count].type = "i2c";
      count++;
    }
  }
  return count;
}

void i2c_print_manifest() {
  i2c_device_t devices[32];
  int n = i2c_scan(devices, 32);
  Serial.printf("{\"devices\":[\n");
  for (int i = 0; i < n; i++) {
    Serial.printf("  {\"addr\":\"0x%02X\",\"name\":\"%s\"}%s\n",
      devices[i].address, devices[i].name, i < n-1 ? "," : "");
  }
  Serial.printf("]}\n");
}
